import{_ as o,o as a,c as r,an as t}from"./chunks/framework.CjbmvEPf.js";const p=JSON.parse('{"title":"Benchmarks","description":"","frontmatter":{},"headers":[],"relativePath":"benchmarks.md","filePath":"benchmarks.md","lastUpdated":null}'),c={name:"benchmarks.md"};function d(i,e,n,s,h,l){return a(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="benchmarks" tabindex="-1">Benchmarks <a class="header-anchor" href="#benchmarks" aria-label="Permalink to &quot;Benchmarks {#benchmarks}&quot;">​</a></h1><p><code>ModifiedDistributions</code> benchmarks each modifier&#39;s hot paths so wrapper overhead is visible and regressions are caught on every pull request.</p><p>The suite (<code>benchmark/benchmarks.jl</code>) evaluates construction, <code>logpdf</code>, <code>pdf</code>, <code>cdf</code>/<code>ccdf</code>, <code>quantile</code> and <code>rand</code> for every modifier around the same base LogNormal, with the bare base as the shared baseline floor:</p><ul><li><p><code>Baseline</code>: the bare base LogNormal.</p></li><li><p><code>Affine</code>: the change-of-variables paths through <code>Y = scale * X + shift</code>.</p></li><li><p><code>Weighted</code>: the <code>logpdf</code> weight paths, scalar and the vectorised <code>Product{Weighted}</code> form.</p></li><li><p><code>Transformed</code>: <code>thin</code> and <code>cumulative</code>, whose forward ops are transparent to every distribution method, so these rows should sit on the baseline.</p></li><li><p><code>Modified</code>: the hazard modification on both analytic links; the identity-link <code>quantile</code> and <code>rand</code> exercise the monotone-bisection cdf inversion, the one non-closed-form path.</p></li><li><p><code>AD gradients</code>: <code>DifferentiationInterface.gradient</code> of every <code>test/ADFixtures</code> scenario across the ForwardDiff, ReverseDiff, Mooncake and Enzyme backends, sharing the fixtures that drive the AD test suite.</p></li></ul><p>Run the suite locally with <code>task benchmark</code>, or compare against <code>main</code> with <code>task benchmark-compare</code> (see <code>benchmark/README.md</code>). On pull requests the <a href="https://github.com/EpiAware/ModifiedDistributions.jl/blob/main/.github/workflows/benchmark.yaml" target="_blank" rel="noreferrer">benchmark workflow</a> benchmarks head and base in separate jobs and posts a single comparison comment. Pushes to <code>main</code> and tags append to the performance history shown below.</p><h2 id="Performance-history" tabindex="-1">Performance history <a class="header-anchor" href="#Performance-history" aria-label="Permalink to &quot;Performance history {#Performance-history}&quot;">​</a></h2><p>The performance timeline (per-benchmark plots and a ratio table) is published to the <a href="https://github.com/EpiAware/ModifiedDistributions.jl/tree/benchmarks/history" target="_blank" rel="noreferrer"><code>benchmarks</code> branch</a> on each push to <code>main</code> and each tagged release.</p>',7)])])}const f=o(c,[["render",d]]);export{p as __pageData,f as default};
